UPDATE TBL_SO_P
SET SCAN_QTY = ISNULL(SCAN_QTY, 0) + 1
WHERE TBL_SO_P_ID = #{tblSoPId}

UPDATE TBL_STOCK
SET STOCK_QTY = STOCK_QTY - 1,
    UPDT_TIME = GETDATE(),
    UPDT_USER = #{userId}
WHERE STOCK_ID = #{stockId}
  AND STOCK_QTY > 0

mapper.select:
SELECT ISNULL(STOCK_QTY, 0)
FROM TBL_STOCK
WHERE STOCK_ID = #{stockId}

mapper.update:
UPDATE TBL_STOCK
SET STOCK_QTY = STOCK_QTY - #{moveQty},
    UPDT_TIME = GETDATE(),
    UPDT_USER = #{userId}
WHERE STOCK_ID = #{stockId}

UPDATE TBL_NOTICE
SET CONFIRM_YN = 'Y', CONFIRM_TIME = GETDATE()
WHERE NOTICE_ID = #{noticeId}

mapper.select:
SELECT * FROM ( SELECT H.[HIST_SEQ] AS histSeq, H.[HIST_TYPE] AS histType, H.[SO_NO] AS soNo, H.[BEFORE_STAT_CD] AS beforeStatCd, (SELECT COMD_NM FROM TBL_COMM_M WHERE COMM_CD = 'SO_STAT_CD' AND COMD_CD = H.BEFORE_STAT_CD) AS beforeStatNm, H.[AFTER_STAT_CD] AS soStatCd, (SELECT COMD_NM FROM TBL_COMM_M WHERE COMM_CD = 'SO_STAT_CD' AND COMD_CD = H.AFTER_STAT_CD) AS afterStatNm, H.[HIST_SAVE_TIME] AS histSaveTime, H.[HIST_SAVE_USER] AS histSaveUser, H.[DLVY_CNFM_DT] AS beforeGiDt, ORG.[DLVY_CNFM_DT] AS giLiftDt, (SELECT AGNT_NM FROM TBL_AGENCY_M WHERE CMPY_CD = ORG.CMPY_CD AND AGNT_CD = ORG.AGNT_CD) AS agntNm, (SELECT LOC_CD FROM TBL_WH_LOC_M WHERE LOC_ID = MTRL.PICKING_LOC_ID) AS locCd, P.[TBL_SO_P_ID] AS tblSoPId, MTRL.[MTRL_CD] AS mtrlCd, MTRL.[MTRL_NM] AS mtrlNm, CASE WHEN MTRL.MTO_YN = 'Y' THEN 'MTO' ELSE '' END AS mto, P.[QTY] AS qty, ISNULL(P.[SCAN_QTY], 0) AS scanQty, H.[MEMO] AS memo, ROW_NUMBER() OVER (PARTITION BY H.[SO_NO] ORDER BY H.[HIST_SAVE_TIME] DESC) AS RN FROM [dbo].[TBL_SO_M_HIST] H INNER JOIN [TBL_SO_M] ORG ON H.[TBL_SO_M_ID] = ORG.[TBL_SO_M_ID] INNER JOIN [TBL_SO_P] P ON ORG.[TBL_SO_M_ID] = P.TBL_SO_M_ID INNER JOIN [TBL_MTRL_M] MTRL ON P.PROD_CD = MTRL.MTRL_CD AND ORG.CMPY_CD = MTRL.CMPY_CD WHERE ORG.CMPY_CD = #{cmpyCd} AND H.[DLVY_CNFM_DT] = REPLACE(#{dlvyDt}, '-', '') AND (CAST(H.[HIST_SAVE_TIME] AS TIME) >= '15:00:00' OR CAST(H.[HIST_SAVE_TIME] AS TIME) < '08:00:00')
AND ( ORG.[SO_STAT_CD] = '0000' -- 취소 OR (ORG.[DLVY_CNFM_DT] IS NOT NULL AND H.[DLVY_CNFM_DT] < ORG.[DLVY_CNFM_DT]) -- 연기 )
) T WHERE T.RN = 1 ORDER BY T.histSaveTime DESC
